arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Use a fixed value — DateTime.UtcNow causes PendingModelChangesWarning in EF 9
    modelBuilder.Entity<Order>().HasData(
        new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
}

arguments.old_str:
void ApplyMigrations(AppDbContext db)
{
    var strategy = db.Database.CreateExecutionStrategy();
    strategy.Execute(() =>
    {
        using var transaction = db.Database.BeginTransaction();
        db.Database.Migrate();
        transaction.Commit();
    });
}

arguments.new_str:
void ApplyMigrations(AppDbContext db)
{
    // EF 9 manages its own transactions and execution strategy inside Migrate().
    // Wrapping in an explicit transaction now throws MigrationsUserTransactionWarning.
    db.Database.Migrate();
}

